// // This SR latch sets Q to 0 when S is high and resets Q to 1 when R is high. If both S and R are high, Q remains unchanged.
module sr_latch(
	input 	S,
	input 	R,
	output reg Q
);

always @(*)
begin
	if (S && R)
		Q <= 1'bx;
	else if (S)
		Q <= 1'b1;
	else if (R)
		Q <= 1'b0;
end

endmodule
